// ── Search engine ─────────────────────────────────────────────────────────────
// Returns top-N matches sorted by relevance score.
// Scoring: exact code match (100) > diagnosis starts-with (60) >
//          all query words in diagnosis (40) > any word in diagnosis (20) >
//          word in body_part or injury_type (10)

export function searchOSIICS(query: string, limit = 10): OSIICSCode[] {
  if (!query || query.trim().length < 2) return []
  const q = query.trim().toLowerCase()
  const words = q.split(/\s+/).filter(w => w.length >= 2)

  const scored = OSIICS_CODES.map(item => {
    const diag = item.diagnosis.toLowerCase()
    const bp   = item.body_part.toLowerCase()
    const it   = item.injury_type.toLowerCase()
    const code = item.code.toLowerCase()
    let score = 0

    if (code === q)                                   score = 100
    else if (code.startsWith(q))                      score = 80
    else if (diag === q)                              score = 90
    else if (diag.startsWith(q))                      score = 60
    else if (diag.includes(q))                        score = 50
    else if (words.length > 1 && words.every(w => diag.includes(w))) score = 40
    else if (words.some(w => diag.includes(w)))       score = 20
    else if (words.some(w => bp.includes(w) || it.includes(w))) score = 10

    return { item, score }
  }).filter(x => x.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, limit)
    .map(x => x.item)

  return scored
}

// Lookup by exact code
export function lookupOSIICS(code: string): OSIICSCode | undefined {
  return OSIICS_CODES.find(c => c.code === code)
}

// All unique body parts
export const OSIICS_BODY_PARTS = [
  ...new Set(OSIICS_CODES.map(c => c.body_part).filter(Boolean))
].sort()

// All unique injury types
export const OSIICS_INJURY_TYPES = [
  ...new Set(OSIICS_CODES.map(c => c.injury_type).filter(Boolean))
].sort()
